    public static LRParserSpec MakeSpec(
        Dictionary<string, ITokenizer>? externals = null,
        NodePropSource[]? propSources = null,
        ContextTracker? context = null)
    {
        var tokenizers = new List<object>();
        tokenizers.Add(externals?["newlines"]!);
        tokenizers.Add(externals?["blockMark"]!);
        tokenizers.Add(externals?["literals"]!);
        tokenizers.Add(externals?["blockLiteral"]!);
        tokenizers.Add(0);
        tokenizers.Add(1);

        return new LRParserSpec
        {
            Version = Version,
            States = States,
            StateData = StateData,
            Goto = Goto,
            NodeNames = NodeNames,
            MaxTerm = MaxTerm,
            RepeatNodeCount = RepeatNodeCount,
            NodeProps = BuildNodeProps(),
            PropSources = propSources,
            SkippedNodes = SkippedNodes,
            TokenData = TokenData,
            Tokenizers = tokenizers.ToArray(),
            TopRules = TopRules,
            Context = context,
            TokenPrec = TokenPrec,
            TermNames = TermNames
        };
    }
